sys_script.script:
(function executeRule(current, previous /*null when async*/) {

	var actionPackageName = current.getDisplayValue();
	var actionPackageSysID = current.getUniqueValue();
	var grConfiguredAction = new GlideRecord('x_taniu_tan_core_configured_action_package');

	grConfiguredAction.addQuery('action_package', actionPackageSysID);

	grConfiguredAction.query();

	while (grConfiguredAction.next()) {
		//Deactivate (but don't delete) the "Configured Action" record.
		grConfiguredAction.setValue('active', false);
		grConfiguredAction.comments = 'This "Configured Package" record was automatically ' +
			'deactivated, since the Tanium Action Package it referenced (' + actionPackageName +
			') was deleted. \n' +
			'This Configured Action has not been deleted in order to preserve the Configured ' +
			'Action Parameters associated with it, but it can be safely deleted if no longer ' +
			'needed. Deleting this Configured Action record will also delete any Configured ' +
			'Action Parameters.';
		grConfiguredAction.update();
	}

})(current, previous);
